import React, { useState } from 'react';

function SignUp({ setToken }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleSignUp = async () => {
    if (password.length < 6) {
      setError('Password must be at least 6 characters long.');
      return;
    }
    setError('');
    
    try {
      // Replace with your backend API endpoint
      const response = await fetch('https://your-backend.com/api/signup', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ username, password }),
      });

      if (response.ok) {
        const data = await response.json();
        setToken(data.token); // Assuming the backend returns a token on successful registration
        setSuccess('Account created successfully!');
      } else {
        const errorData = await response.json();
        setError(errorData.message || 'Failed to create an account. Please try again.');
      }
    } catch (err) {
      setError('An error occurred. Please try again.');
    }
  };

  return (
    <div style={formStyle}>
      <h2 style={formHeaderStyle}>Sign Up</h2>
      <input
        type="text"
        placeholder="Username"
        value={username}
        onChange={(e) => setUsername(e.target.value)}
        style={inputStyle}
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        style={inputStyle}
      />
      {error && <p style={errorStyle}>{error}</p>}
      {success && <p style={successStyle}>{success}</p>}
      <button onClick={handleSignUp} style={buttonStyle}>
        Sign Up
      </button>
    </div>
  );
}

// Styles
const formStyle = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  gap: '10px',
};

const formHeaderStyle = {
  color: '#ffffff',
};

const inputStyle = {
  width: '80%',
  padding: '10px',
  borderRadius: '5px',
  border: '1px solid #ccc',
  backgroundColor: '#1e1e1e',
  color: '#ffffff',
};

const buttonStyle = {
  padding: '10px 20px',
  borderRadius: '5px',
  border: 'none',
  backgroundColor: '#4caf50',
  color: '#ffffff',
  cursor: 'pointer',
};

const errorStyle = {
  color: '#ff6b6b',
  fontSize: '0.9em',
};

export default SignUp;
